import { useNavigate, useLocation } from "react-router-dom";
import { useEffect } from "react";
import { toast } from "sonner";
import { useTranslation } from "react-i18next";
import { useUserRole } from "@/hooks/useUserRole";
import CreateRecipeWizard from "@/components/community/recipe/CreateRecipeWizard";

const CreateRecipePage = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { t } = useTranslation();
  const { isAdmin, isMerchant, isSupervisor, isLoading } = useUserRole();
  const prefillFromAI = (location.state as any)?.prefillFromAI || null;

  const canCreate = isAdmin || isMerchant || isSupervisor;

  useEffect(() => {
    if (!isLoading && !canCreate) {
      toast.error(t("common.noPermission", "您没有权限执行此操作"));
      navigate("/community/create", { replace: true });
    }
  }, [isLoading, canCreate, navigate, t]);

  if (isLoading || !canCreate) return null;

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <CreateRecipeWizard
        onClose={() => navigate("/community/create")}
        onSuccess={() => navigate("/community")}
        prefillFromAI={prefillFromAI}
      />
    </div>
  );
};

export default CreateRecipePage;
